<template>
  <div class="listone_wrapper">
    <div>
      {{showTest}}
    </div>
    <h1>
      {{title}}
    </h1>
    <ul>
      <li v-for="(p,i) in showList" :key="i">
        <span>
          {{p.name}}
        </span>
        <span>
          {{p.price}}
        </span>
      </li>
    </ul>

  </div>
</template>
<script>
  import {
    mapGetters
  } from 'vuex'
  export default {
    data() {
      return {
        title: `list-one`
      }
    },
    computed: {
      showList() {
        return this.$store.state.person
      },
      // ...mapGetters([
      //   "test"
      // ])
      showTest(){
        return this.$store.getters.test
      }
    }
  }
</script>
<style scoped>
  .listone_wrapper {
    border: 6px dashed red;
    background: lightcoral;
  }
</style>