<template>
  <div class="listtwo_wrapper">
    <h1>
      {{title}}
    </h1>
    <ul>
      <li v-for="(p,i) in person" :key="i">
        <span>
          {{p.name}}
        </span>
        <span>
          {{p.price}}
        </span>
      </li>
    </ul>
    <div>
      {{test}}
    </div>

    <div>
      {{books}}
    </div>
  </div>
</template>
<script>
  import {
    mapState,
    mapGetters
  } from 'vuex'
  export default {
    data() {
      return {
        title: `list-two`
      }
    },
    methods: {
    },
    computed: {
      ...mapState([
        "person",
        "books"
      ]),
      ...mapGetters([
        "test"
      ])
    }
  }
</script>
<style scoped>
  .listtwo_wrapper {
    border: 6px dotted burlywood;
    background: lawngreen;
  }
</style>